import csv
from collections import defaultdict

counts = defaultdict(lambda: defaultdict(int))
# structure: counts[severity][treatment][outcome]
# plus aggregate: counts['total'][treatment][outcome]

with open('/workspace/outcomes.csv', 'r') as f:
    reader = csv.DictReader(f)
    for row in reader:
        sev = row['severity']
        treat = row['treatment']
        out = row['outcome']

        counts[sev][treat][out] += 1
        counts['total'][treat][out] += 1

def rate(success, total):
    return success / total if total > 0 else 0

results = {
    "aggregate_rate_a": rate(counts['total']['A']['success'], sum(counts['total']['A'].values())),
    "aggregate_rate_b": rate(counts['total']['B']['success'], sum(counts['total']['B'].values())),
    "stratified_rates": {
        "mild": {
            "A": rate(counts['mild']['A']['success'], sum(counts['mild']['A'].values())),
            "B": rate(counts['mild']['B']['success'], sum(counts['mild']['B'].values()))
        },
        "severe": {
            "A": rate(counts['severe']['A']['success'], sum(counts['severe']['A'].values())),
            "B": rate(counts['severe']['B']['success'], sum(counts['severe']['B'].values()))
        }
    }
}

import json
print(json.dumps(results, indent=2))

# Also print raw counts for sanity check
print("\nRaw counts:")
for k, v in counts.items():
    print(f"{k}: {dict(v)}")

